104→// ---------------------------------------------------------------------------
105→// Runner detection
106→// ---------------------------------------------------------------------------
107→
108→/// Detected test runner with its project root.
109→#[derive(Debug)]
110→pub struct DetectedRunner {
111→    pub kind: RunnerKind,
112→    pub root: PathBuf,
113→}
114→
115→/// Auto-detect available test runners by looking for manifest files.
116→pub fn detect_runners(root: &Path) -> Vec<DetectedRunner> {
117→    let mut runners = Vec::new();
118→
119→    if root.join("Cargo.toml").exists() {
120→        runners.push(DetectedRunner {
121→            kind: RunnerKind::Cargo,
122→            root: root.to_path_buf(),
123→        });
124→    }
125→    if root.join("package.json").exists() {
126→        runners.push(DetectedRunner {
127→            kind: RunnerKind::Vitest,
128→            root: root.to_path_buf(),
129→        });
130→    }
131→    if root.join("go.mod").exists() {
132→        runners.push(DetectedRunner {
133→            kind: RunnerKind::GoTest,
134→            root: root.to_path_buf(),
135→        });
136→    }
137→
138→    // Also check subdirectories for multi-crate/multi-package repos
139→    if let Ok(entries) = std::fs::read_dir(root) {
140→        for entry in entries.flatten() {
141→            let path = entry.path();
142→            if !path.is_dir() {
143→                continue;
144→            }
145→            let dir_name = path.file_name().and_then(|n| n.to_str()).unwrap_or("");
146→            // Skip hidden dirs, target, node_modules
147→            if dir_name.starts_with('.') || dir_name == "target" || dir_name == "node_modules" {
148→                continue;
149→            }
150→
151→            if path.join("Cargo.toml").exists()
152→                && !runners.iter().any(|r| r.kind == RunnerKind::Cargo && r.root == path)
153→            {
154→                // Skip sub-crates if root has Cargo.toml (workspace handles them)
155→                // Only add if no root-level Cargo.toml
156→                if !root.join("Cargo.toml").exists() {
157→                    runners.push(DetectedRunner {
158→                        kind: RunnerKind::Cargo,
159→                        root: path.clone(),
160→                    });
161→                }
162→            }
163→            if path.join("package.json").exists()
164→                && !runners.iter().any(|r| r.kind == RunnerKind::Vitest && r.root == path)
165→            {
166→                runners.push(DetectedRunner {
167→                    kind: RunnerKind::Vitest,
168→                    root: path.clone(),
169→                });
170→            }
171→            if path.join("go.mod").exists()
172→                && !runners.iter().any(|r| r.kind == RunnerKind::GoTest && r.root == path)
173→            {
174→                runners.push(DetectedRunner {
175→                    kind: RunnerKind::GoTest,
176→                    root: path,
177→                });
178→            }
179→        }
180→    }
181→
182→    runners
183→}
