241→/// Run tests with coverage instrumentation, parsing coverage output into
242→/// a test→files mapping.
243→pub fn run_with_coverage(
244→    runner: &DetectedRunner,
245→    project_root: &Path,
246→) -> Result<CoverageOutput, TiaError> {
247→    match runner.kind {
248→        RunnerKind::Cargo => run_cargo_with_coverage(&runner.root, project_root),
249→        RunnerKind::GoTest => run_go_with_coverage(&runner.root, project_root),
250→        RunnerKind::Vitest => run_vitest_with_coverage(&runner.root, project_root),
251→    }
252→}
