337→// ---------------------------------------------------------------------------
338→// Go coverage
339→// ---------------------------------------------------------------------------
340→
341→fn run_go_with_coverage(
342→    go_root: &Path,
343→    project_root: &Path,
344→) -> Result<CoverageOutput, TiaError> {
345→    let start = Instant::now();
346→    let cover_file = go_root.join("coverage.out");
347→
348→    let output = Command::new("go")
349→        .args([
350→            "test",
351→            "./...",
352→            &format!("-coverprofile={}", cover_file.to_string_lossy()),
353→        ])
354→        .current_dir(go_root)
355→        .output()
356→        .map_err(|e| TiaError::Runner {
357→            message: format!("go test failed: {e}"),
358→        })?;
359→
360→    let run_result = TestRunResult {
361→        success: output.status.success(),
362→        runner: RunnerKind::GoTest,
363→        duration: start.elapsed(),
364→        stdout: String::from_utf8_lossy(&output.stdout).to_string(),
365→        stderr: String::from_utf8_lossy(&output.stderr).to_string(),
366→    };
367→
368→    let test_file_map = if cover_file.exists() {
369→        parse_go_coverprofile(&cover_file, go_root, project_root)
370→    } else {
371→        BTreeMap::new()
372→    };
373→
374→    // Clean up coverage file
375→    let _ = std::fs::remove_file(&cover_file);
376→
377→    Ok(CoverageOutput {
378→        test_file_map,
379→        run_result,
380→    })
381→}
382→
383→/// Parse Go coverprofile format into a test→files map.
384→/// Go coverprofile lines look like: `package/file.go:line.col,line.col count`
385→/// We group all covered files under the Go module's test identifier.
386→pub fn parse_go_coverprofile(
387→    cover_file: &Path,
388→    go_root: &Path,
389→    project_root: &Path,
390→) -> BTreeMap<String, Vec<String>> {
391→    let mut map = BTreeMap::new();
392→    let contents = match std::fs::read_to_string(cover_file) {
393→        Ok(c) => c,
394→        Err(_) => return map,
395→    };
396→
397→    let module_name = go_root
398→        .file_name()
399→        .and_then(|n| n.to_str())
400→        .unwrap_or("go");
401→
402→    let mut files = std::collections::HashSet::new();
403→    for line in contents.lines() {
404→        if line.starts_with("mode:") {
405→            continue;
406→        }
407→        // Format: <import-path>/<file>:<start>.<col>,<end>.<col> <count>
408→        if let Some(colon_pos) = line.find(':') {
409→            let file_path = &line[..colon_pos];
410→            // Convert import path to relative path
411→            // e.g., "github.com/user/repo/pkg/file.go" → find the .go file relative to project
412→            if let Some(go_file) = file_path.rsplit('/').next() {
413→                // Try to find this file relative to go_root
414→                let candidates = find_go_file(go_root, go_file);
415→                for candidate in candidates {
416→                    if let Ok(rel) = candidate.strip_prefix(project_root) {
417→                        files.insert(rel.to_string_lossy().to_string());
418→                    }
419→                }
420→            }
421→        }
422→    }
423→
424→    if !files.is_empty() {
425→        let mut file_list: Vec<String> = files.into_iter().collect();
426→        file_list.sort();
427→        map.insert(format!("{module_name}::all"), file_list);
428→    }
429→
430→    map
431→}
432→
433→fn find_go_file(root: &Path, filename: &str) -> Vec<PathBuf> {
434→    let mut results = Vec::new();
435→    if let Ok(entries) = std::fs::read_dir(root) {
436→        for entry in entries.flatten() {
437→            let path = entry.path();
438→            if path.is_dir() {
439→                let name = path.file_name().and_then(|n| n.to_str()).unwrap_or("");
440→                if !name.starts_with('.') && name != "vendor" {
441→                    results.extend(find_go_file(&path, filename));
442→                }
443→            } else if path.file_name().is_some_and(|n| n == filename) {
444→                results.push(path);
445→            }
446→        }
447→    }
448→    results
449→}
