452→// Vitest coverage
453→// ---------------------------------------------------------------------------
454→
455→fn run_vitest_with_coverage(
456→    ts_root: &Path,
457→    project_root: &Path,
458→) -> Result<CoverageOutput, TiaError> {
459→    let start = Instant::now();
460→
461→    let output = Command::new("npx")
462→        .args(["vitest", "run", "--coverage", "--coverage.reporter=json"])
463→        .current_dir(ts_root)
464→        .output()
465→        .map_err(|e| TiaError::Runner {
466→            message: format!("vitest failed: {e}"),
467→        })?;
468→
469→    let run_result = TestRunResult {
470→        success: output.status.success(),
471→        runner: RunnerKind::Vitest,
472→        duration: start.elapsed(),
473→        stdout: String::from_utf8_lossy(&output.stdout).to_string(),
474→        stderr: String::from_utf8_lossy(&output.stderr).to_string(),
475→    };
476→
477→    // Parse Istanbul coverage JSON if available
478→    let coverage_file = ts_root.join("coverage/coverage-final.json");
479→    let test_file_map = if coverage_file.exists() {
480→        parse_istanbul_coverage(&coverage_file, project_root)
481→    } else {
482→        BTreeMap::new()
483→    };
484→
485→    Ok(CoverageOutput {
486→        test_file_map,
487→        run_result,
488→    })
489→}
490→
491→/// Parse Istanbul coverage-final.json into a test→files map.
492→/// The JSON keys are absolute file paths; values contain coverage data.
493→/// We group all covered files under a single test identifier.
494→pub fn parse_istanbul_coverage(
495→    coverage_file: &Path,
496→    project_root: &Path,
497→) -> BTreeMap<String, Vec<String>> {
498→    let mut map = BTreeMap::new();
499→    let contents = match std::fs::read_to_string(coverage_file) {
500→        Ok(c) => c,
501→        Err(_) => return map,
502→    };
503→
504→    let parsed: serde_json::Value = match serde_json::from_str(&contents) {
505→        Ok(v) => v,
506→        Err(_) => return map,
507→    };
508→
509→    let ts_root = coverage_file
510→        .parent()
511→        .and_then(|p| p.parent())
512→        .and_then(|p| p.file_name())
513→        .and_then(|n| n.to_str())
514→        .unwrap_or("ts");
515→
516→    if let Some(obj) = parsed.as_object() {
517→        let mut files = Vec::new();
518→        for key in obj.keys() {
519→            let abs_path = Path::new(key);
520→            if let Ok(rel) = abs_path.strip_prefix(project_root) {
521→                files.push(rel.to_string_lossy().to_string());
522→            }
523→        }
524→        files.sort();
525→        if !files.is_empty() {
526→            map.insert(format!("{ts_root}::all"), files);
527→        }
528→    }
529→
530→    map
531→}
