534→// Tier execution
535→// ---------------------------------------------------------------------------
536→
537→/// Run a complete test tier, returning success/failure.
538→/// Executes the tier's predefined commands in order.
539→pub fn run_tier(tier: TestTier, project_root: &Path) -> Result<bool, TiaError> {
540→    match tier {
541→        TestTier::Quick => run_tier_quick(project_root),
542→        TestTier::Standard => run_tier_standard(project_root),
543→        TestTier::Full => run_tier_full(project_root),
544→        TestTier::E2e => run_tier_e2e(project_root),
545→    }
546→}
547→
548→fn run_tier_quick(root: &Path) -> Result<bool, TiaError> {
549→    let output = Command::new("cargo")
550→        .args(["test"])
551→        .current_dir(root)
552→        .status()
553→        .map_err(|e| TiaError::Runner {
554→            message: format!("cargo test failed: {e}"),
555→        })?;
556→    Ok(output.success())
557→}
558→
559→fn run_tier_standard(root: &Path) -> Result<bool, TiaError> {
560→    if !run_tier_quick(root)? {
561→        return Ok(false);
562→    }
563→    let output = Command::new("cargo")
564→        .args(["clippy", "--", "-D", "warnings"])
565→        .current_dir(root)
566→        .status()
567→        .map_err(|e| TiaError::Runner {
568→            message: format!("cargo clippy failed: {e}"),
569→        })?;
570→    Ok(output.success())
571→}
572→
573→fn run_tier_full(root: &Path) -> Result<bool, TiaError> {
574→    if !run_tier_standard(root)? {
575→        return Ok(false);
576→    }
577→
578→    // TypeScript tests
579→    let ts_dir = root.join("shatter-ts");
580→    if ts_dir.exists() {
581→        let output = Command::new("npm")
582→            .args(["test"])
583→            .current_dir(&ts_dir)
584→            .status()
585→            .map_err(|e| TiaError::Runner {
586→                message: format!("npm test failed: {e}"),
587→            })?;
588→        if !output.success() {
589→            return Ok(false);
590→        }
591→    }
592→
593→    // Go tests
594→    let go_dir = root.join("shatter-go");
595→    if go_dir.exists() {
596→        let output = Command::new("go")
597→            .args(["test", "./..."])
598→            .current_dir(&go_dir)
599→            .status()
600→            .map_err(|e| TiaError::Runner {
601→                message: format!("go test failed: {e}"),
602→            })?;
603→        if !output.success() {
604→            return Ok(false);
605→        }
606→    }
607→
608→    Ok(true)
609→}
610→
611→fn run_tier_e2e(root: &Path) -> Result<bool, TiaError> {
612→    if !run_tier_full(root)? {
613→        return Ok(false);
614→    }
615→    let output = Command::new("cargo")
616→        .args(["test", "--test", "e2e_concolic"])
617→        .current_dir(root)
618→        .status()
619→        .map_err(|e| TiaError::Runner {
620→            message: format!("e2e test failed: {e}"),
621→        })?;
622→    Ok(output.success())
623→}
