  1→//! Coverage metrics for concolic exploration results.
  2→//!
  3→//! After exploration, reports what percentage of discovered branches were found
  4→//! by each method (Z3 solving, random/boundary generation, user-provided inputs)
  5→//! and what fraction of branch conditions the frontend expressed as symbolic
  6→//! expressions vs opaque unknowns.
  7→
  8→use std::collections::{HashMap, HashSet};
  9→
 10→use serde::{Deserialize, Serialize};
 11→
 12→use crate::execution_record::SymConstraint;
 13→use crate::explorer::ObservationOutput;
 14→use crate::orchestrator::ExploreResult;
 15→use crate::protocol::{BranchInfo, ExecuteResult, FunctionAnalysis};
 16→
 17→/// How a branch was discovered during exploration.
 18→#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash, Serialize, Deserialize)]
 19→#[serde(rename_all = "snake_case")]
 20→pub enum DiscoveryMethod {
 21→    /// Found by Z3 constraint solving (negating a path constraint).
 22→    Z3,
 23→    /// Found by random or boundary input generation.
 24→    Random,
 25→    /// Found via user-provided inputs.
 26→    UserProvided,
 27→    /// Found by parameter drilling on a stalled frontier.
 28→    Drilled,
 29→    /// Found by boundary search between true/false witnesses.
 30→    BoundarySearch,
 31→}
 32→
 33→/// Percentage breakdown of discovery methods.
 34→#[derive(Debug, Clone, PartialEq, Serialize, Deserialize)]
 35→pub struct MethodPercentages {
 36→    /// Percentage of branches found by Z3 solving.
 37→    pub z3_pct: f64,
 38→    /// Percentage of branches found by random/boundary generation.
 39→    pub random_pct: f64,
 40→    /// Percentage of branches found by user-provided inputs.
 41→    pub user_provided_pct: f64,
 42→    /// Percentage of branches still uncovered.
 43→    pub uncovered_pct: f64,
 44→}
 45→
 46→/// Coverage metrics summarizing how effective the concolic approach was.
 47→#[derive(Debug, Clone, Default, PartialEq, Serialize, Deserialize)]
 48→pub struct CoverageMetrics {
 49→    /// Total number of branch points in the function.
 50→    pub total_branches: usize,
 51→    /// Branches discovered by Z3 constraint solving.
 52→    pub z3_solved: usize,
 53→    /// Branches discovered by random/boundary generation.
 54→    pub random_found: usize,
 55→    /// Branches discovered via user-provided inputs.
 56→    pub user_provided: usize,
 57→    /// Branches that remain uncovered.
 58→    pub uncovered: usize,
 59→    /// Number of branch constraints expressed as SymExpr (solvable by Z3).
 60→    pub symexpr_count: usize,
 61→    /// Number of branch constraints that were Unknown (opaque to solver).
 62→    pub unknown_count: usize,
 63→}
 64→
 65→impl CoverageMetrics {
 66→    /// Compute percentage breakdown by discovery method.
 67→    ///
 68→    /// Returns zero percentages when there are no branches (avoids division by zero).
 69→    pub fn percentages(&self) -> MethodPercentages {
 70→        if self.total_branches == 0 {
 71→            return MethodPercentages {
 72→                z3_pct: 0.0,
 73→                random_pct: 0.0,
 74→                user_provided_pct: 0.0,
 75→                uncovered_pct: 0.0,
 76→            };
 77→        }
 78→
 79→        let total = self.total_branches as f64;
 80→        MethodPercentages {
 81→            z3_pct: self.z3_solved as f64 / total * 100.0,
 82→            random_pct: self.random_found as f64 / total * 100.0,
 83→            user_provided_pct: self.user_provided as f64 / total * 100.0,
 84→            uncovered_pct: self.uncovered as f64 / total * 100.0,
 85→        }
 86→    }
 87→
 88→    /// Symbolic expression coverage ratio: what fraction of branch conditions
 89→    /// the frontend could express as SymExpr (vs Unknown).
 90→    ///
 91→    /// Returns 0.0 if there are no constraints at all.
 92→    pub fn symexpr_ratio(&self) -> f64 {
 93→        let total = self.symexpr_count + self.unknown_count;
 94→        if total == 0 {
 95→            return 0.0;
 96→        }
 97→        self.symexpr_count as f64 / total as f64
 98→    }
 99→
100→    /// Build metrics from a list of per-branch discovery results and constraints.
101→    ///
102→    /// `discoveries` maps each covered branch to the method that first found it.
103→    /// `total_branches` is the total number of branch points (from static analysis).
104→    /// `constraints` is the set of all constraints observed across executions.
105→    pub fn from_exploration(
106→        total_branches: usize,
107→        discoveries: &[(u32, DiscoveryMethod)],
108→        constraints: &[SymConstraint],
109→    ) -> Self {
110→        let mut z3_solved = 0usize;
111→        let mut random_found = 0usize;
112→        let mut user_provided = 0usize;
113→
114→        for (_, method) in discoveries {
115→            match method {
116→                DiscoveryMethod::Z3 => z3_solved += 1,
117→                DiscoveryMethod::Random
118→                | DiscoveryMethod::Drilled
119→                | DiscoveryMethod::BoundarySearch => random_found += 1,
120→                DiscoveryMethod::UserProvided => user_provided += 1,
121→            }
122→        }
123→
124→        let covered = z3_solved + random_found + user_provided;
125→        let uncovered = total_branches.saturating_sub(covered);
126→
127→        let mut symexpr_count = 0usize;
128→        let mut unknown_count = 0usize;
129→
130→        for constraint in constraints {
131→            match constraint {
132→                SymConstraint::Expr { .. } => symexpr_count += 1,
133→                SymConstraint::Unknown { .. } => unknown_count += 1,
134→            }
135→        }
136→
137→        Self {
138→            total_branches,
139→            z3_solved,
140→            random_found,
141→            user_provided,
142→            uncovered,
143→            symexpr_count,
144→            unknown_count,
145→        }
146→    }
147→
148→    /// Additively merge `other` into `self`.
149→    ///
150→    /// Each counter is summed. The caller must ensure no double-counting
151→    /// (e.g., each function appears in exactly one batch).
152→    pub fn merge(&mut self, other: &CoverageMetrics) {
153→        self.total_branches += other.total_branches;
154→        self.z3_solved += other.z3_solved;
155→        self.random_found += other.random_found;
156→        self.user_provided += other.user_provided;
157→        self.uncovered += other.uncovered;
158→        self.symexpr_count += other.symexpr_count;
159→        self.unknown_count += other.unknown_count;
160→    }
161→}
162→
163→/// Format coverage metrics as a human-readable summary block.
164→pub fn format_coverage_metrics(
165→    metrics: &CoverageMetrics,
166→    style: &crate::report_style::ReportStyle,
167→) -> String {
168→    let mut out = String::new();
169→    let pct = metrics.percentages();
170→
171→    let covered = metrics.total_branches.saturating_sub(metrics.uncovered);
172→    let branch_pct = if metrics.total_branches > 0 {
173→        covered as f64 / metrics.total_branches as f64 * 100.0
174→    } else {
175→        0.0
176→    };
177→
178→    if metrics.total_branches == 0 {
179→        out.push_str(&format!(
180→            "  {dim}Branches: 0 (no branches){reset}\n",
181→            dim = style.dim,
182→            reset = style.reset,
183→        ));
184→        return out;
185→    }
186→
187→    out.push_str(&format!(
188→        "  Branches: {covered}/{total} ({pct}) {indicator}\n",
189→        total = metrics.total_branches,
190→        pct = style.color_coverage_pct(branch_pct),
191→        indicator = style.coverage_indicator(branch_pct),
192→    ));
193→
194→    // Detailed breakdown in dim text
195→    let mut details = Vec::new();
196→    if metrics.z3_solved > 0 {
197→        details.push(format!("Z3: {} ({:.0}%)", metrics.z3_solved, pct.z3_pct));
198→    }
199→    if metrics.random_found > 0 {
200→        details.push(format!(
201→            "random: {} ({:.0}%)",
202→            metrics.random_found, pct.random_pct
203→        ));
204→    }
205→    if metrics.user_provided > 0 {
206→        details.push(format!(
207→            "user: {} ({:.0}%)",
208→            metrics.user_provided, pct.user_provided_pct
209→        ));
210→    }
211→    if metrics.uncovered > 0 {
212→        details.push(format!(
213→            "{red}uncovered: {} ({:.0}%){reset}",
214→            metrics.uncovered,
215→            pct.uncovered_pct,
216→            red = style.red,
217→            reset = style.reset,
218→        ));
219→    }
220→    if !details.is_empty() {
221→        out.push_str(&format!(
222→            "  {dim}[{details}]{reset}\n",
223→            details = details.join(", "),
224→            dim = style.dim,
225→            reset = style.reset,
226→        ));
227→    }
228→
229→    let constraint_total = metrics.symexpr_count + metrics.unknown_count;
230→    if constraint_total > 0 {
231→        let ratio_pct = metrics.symexpr_ratio() * 100.0;
232→        out.push_str(&format!(
233→            "  {dim}Symbolic: {}/{} constraints ({:.0}%){reset}\n",
234→            metrics.symexpr_count, constraint_total, ratio_pct,
235→            dim = style.dim,
236→            reset = style.reset,
237→        ));
238→    }
239→
240→    out
241→}
