243→/// Why a branch was selected as a GA target.
244→#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash, Serialize, Deserialize)]
245→#[serde(rename_all = "snake_case")]
246→pub enum TargetReason {
247→    /// Branch was never discovered by any method.
248→    Uncovered,
249→    /// Branch was observed but its constraint is Unknown (opaque to solver).
250→    OpaqueConstraint,
251→}
252→
253→/// A branch that the Genetic Algorithm should target for coverage.
254→#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize)]
255→pub struct TargetBranch {
256→    /// Unique branch identifier within the function.
257→    pub branch_id: u32,
258→    /// Source line number of the branch.
259→    pub line: u32,
260→    /// Why this branch is targeted.
261→    pub reason: TargetReason,
262→    /// Hint about the constraint to guide mutation strategy.
263→    pub constraint_hint: Option<String>,
264→}
265→
266→/// Extract unsolved branch targets from a random exploration result.
267→///
268→/// Compares the static branch list from `analysis` against branches discovered
269→/// during exploration to identify targets the GA should focus on.
270→pub fn extract_targets(
271→    analysis: &FunctionAnalysis,
272→    result: &ObservationOutput,
273→) -> Vec<TargetBranch> {
274→    extract_targets_inner(&analysis.branches, &result.discoveries, &result.raw_results)
275→}
276→
277→/// Extract unsolved branch targets from a concolic exploration result.
278→///
279→/// Same logic as [`extract_targets`] but accepts the orchestrator's result type.
280→pub fn extract_targets_concolic(
281→    analysis: &FunctionAnalysis,
282→    result: &ExploreResult,
283→) -> Vec<TargetBranch> {
284→    extract_targets_inner(&analysis.branches, &result.discoveries, &result.raw_results)
285→}
286→
287→/// Core target extraction logic operating on slices.
288→///
289→/// A branch is targeted if:
290→/// - It was never discovered (not in `discoveries`) → `TargetReason::Uncovered`
291→/// - It was discovered but its runtime constraint is `Unknown` → `TargetReason::OpaqueConstraint`
292→fn extract_targets_inner(
293→    branches: &[BranchInfo],
294→    discoveries: &[(u32, DiscoveryMethod)],
295→    raw_results: &[(Vec<serde_json::Value>, ExecuteResult)],
296→) -> Vec<TargetBranch> {
297→    let discovered: HashSet<u32> = discoveries.iter().map(|(id, _)| *id).collect();
298→
299→    // Collect opaque constraint hints from runtime branch decisions.
300→    let mut opaque_hints: HashMap<u32, String> = HashMap::new();
301→    for (_, exec) in raw_results {
302→        for decision in &exec.branch_path {
303→            if let SymConstraint::Unknown { hint } = &decision.constraint {
304→                opaque_hints
305→                    .entry(decision.branch_id)
306→                    .or_insert_with(|| hint.clone());
307→            }
308→        }
309→    }
310→
311→    let mut targets: Vec<TargetBranch> = Vec::new();
312→    for branch in branches {
313→        if !discovered.contains(&branch.id) {
314→            targets.push(TargetBranch {
315→                branch_id: branch.id,
316→                line: branch.line,
317→                reason: TargetReason::Uncovered,
318→                constraint_hint: if branch.condition_text.is_empty() {
319→                    None
320→                } else {
321→                    Some(branch.condition_text.clone())
322→                },
323→            });
324→        } else if let Some(hint) = opaque_hints.get(&branch.id) {
325→            targets.push(TargetBranch {
326→                branch_id: branch.id,
327→                line: branch.line,
328→                reason: TargetReason::OpaqueConstraint,
329→                constraint_hint: if hint.is_empty() { None } else { Some(hint.clone()) },
330→            });
331→        }
332→    }
333→
334→    targets.sort_by_key(|t| t.branch_id);
335→    targets
336→}
