//! Greedy submodular maximization for test case prioritization.
//!
//! Orders tests by marginal coverage per unit execution time:
//! at each step, pick the test that covers the most new lines per second,
//! then mark its lines as covered and repeat.
//!
//! Optionally applies change-recency weighting so recently-modified files
//! contribute more to a test's score.
//!
//! Pipeline integration: TIA (test_impact) selects *which* tests to run;
//! this module decides *in what order* to run them, optionally truncating
//! to a time budget.

use std::collections::{HashMap, HashSet};
use std::path::Path;
use std::process::Command;
use std::time::Duration;

use serde::{Deserialize, Serialize};

// ---------------------------------------------------------------------------
// Constants
// ---------------------------------------------------------------------------

/// Default recency half-life in days: files modified this many days ago
/// receive half the weight of files modified today.
pub const DEFAULT_RECENCY_HALF_LIFE_DAYS: f64 = 30.0;

/// Minimum execution time assigned to any test, preventing division by zero
/// and avoiding infinite scores for tests with near-zero recorded time.
pub const MIN_EXECUTION_TIME: Duration = Duration::from_millis(1);

// ---------------------------------------------------------------------------
// Data types
// ---------------------------------------------------------------------------

/// Per-test input to the prioritizer.
#[derive(Debug, Clone, Serialize, Deserialize, PartialEq)]
pub struct TestCoverageInfo {
    /// Unique test identifier (same key used in the TIA coverage map).
    pub test_id: String,
    /// Source lines this test covers, keyed by relative file path.
    pub covered_lines: HashMap<String, HashSet<u32>>,
    /// Recorded execution duration. Clamped to [`MIN_EXECUTION_TIME`] internally.
    pub execution_time: Duration,
}

/// A single entry in the prioritized ordering.
#[derive(Debug, Clone, Serialize, Deserialize, PartialEq)]
pub struct PrioritizedTest {
    pub test_id: String,
    /// Marginal lines covered at the point this test was selected.
    pub marginal_coverage: usize,
    /// Score (marginal_lines / seconds) at selection time.
    pub score: f64,
    /// Cumulative wall-clock time through this test (sum of execution_times so far).
    pub cumulative_time: Duration,
}

/// Output of the prioritization algorithm.
#[derive(Debug, Clone, Serialize, Deserialize, PartialEq)]
pub struct PrioritizationResult {
    /// Tests in prioritized order.
    pub ordered: Vec<PrioritizedTest>,
    /// Total lines covered by all selected tests.
    pub total_lines_covered: usize,
    /// Total execution time of all selected tests.
    pub total_time: Duration,
    /// Number of tests excluded by budget (0 if no budget).
    pub budget_excluded: usize,
}

/// Configuration for the prioritization pass.
#[derive(Debug, Clone)]
pub struct PrioritizeConfig {
    /// Optional time budget. Tests beyond this cumulative time are excluded.
    pub budget: Option<Duration>,
    /// Per-file recency weights (file path → weight in [0, 1]).
    /// If empty, all lines are weighted equally.
    pub recency_weights: HashMap<String, f64>,
}

impl Default for PrioritizeConfig {
    fn default() -> Self {
        Self {
            budget: None,
            recency_weights: HashMap::new(),
        }
    }
}

// ---------------------------------------------------------------------------
// Core algorithm
// ---------------------------------------------------------------------------

/// Greedy submodular maximization: repeatedly select the test with the
/// highest (weighted marginal coverage) / execution_time, until all tests
/// are ordered or the budget is exhausted.
pub fn prioritize(
    tests: &[TestCoverageInfo],
    config: &PrioritizeConfig,
) -> PrioritizationResult {
    if tests.is_empty() {
        return PrioritizationResult {
            ordered: Vec::new(),
            total_lines_covered: 0,
            total_time: Duration::ZERO,
            budget_excluded: 0,
        };
    }

    let mut covered: HashSet<(String, u32)> = HashSet::new();
    let mut remaining: Vec<usize> = (0..tests.len()).collect();
    let mut ordered = Vec::with_capacity(tests.len());
    let mut cumulative = Duration::ZERO;
    let mut budget_excluded = 0usize;

    while !remaining.is_empty() {
        let mut best_idx_in_remaining: Option<usize> = None;
        let mut best_score = f64::NEG_INFINITY;
        let mut best_marginal = 0usize;

        for (ri, &ti) in remaining.iter().enumerate() {
            let marginal = marginal_coverage(&tests[ti], &covered, &config.recency_weights);
            let secs = effective_seconds(tests[ti].execution_time);
            let score = marginal / secs;

            if score > best_score || (score == best_score && best_idx_in_remaining.is_none()) {
                best_score = score;
                best_marginal = marginal_count(&tests[ti], &covered);
                best_idx_in_remaining = Some(ri);
            }
        }

        let ri = match best_idx_in_remaining {
            Some(ri) => ri,
            None => break,
        };
        let ti = remaining.remove(ri);
        let test = &tests[ti];

        let new_cumulative = cumulative + clamp_time(test.execution_time);

        // Budget check: if adding this test exceeds the budget, exclude remaining
        if let Some(budget) = config.budget {
            if new_cumulative > budget {
                // This test and all remaining are excluded
                budget_excluded = 1 + remaining.len();
                break;
            }
        }

        cumulative = new_cumulative;

        // Mark lines as covered
        for (file, lines) in &test.covered_lines {
            for &line in lines {
                covered.insert((file.clone(), line));
            }
        }

        ordered.push(PrioritizedTest {
            test_id: test.test_id.clone(),
            marginal_coverage: best_marginal,
            score: best_score,
            cumulative_time: cumulative,
        });
    }

    PrioritizationResult {
        total_lines_covered: covered.len(),
        total_time: cumulative,
        ordered,
        budget_excluded,
    }
}

/// Weighted marginal coverage: sum of recency weights for each new line.
fn marginal_coverage(
    test: &TestCoverageInfo,
    already_covered: &HashSet<(String, u32)>,
    recency_weights: &HashMap<String, f64>,
) -> f64 {
    let mut total = 0.0f64;
    for (file, lines) in &test.covered_lines {
        let weight = recency_weights.get(file).copied().unwrap_or(1.0);
        for &line in lines {
            if !already_covered.contains(&(file.clone(), line)) {
                total += weight;
            }
        }
    }
    total
}

/// Unweighted marginal line count (for reporting).
fn marginal_count(
    test: &TestCoverageInfo,
    already_covered: &HashSet<(String, u32)>,
) -> usize {
    let mut count = 0usize;
    for (file, lines) in &test.covered_lines {
        for &line in lines {
            if !already_covered.contains(&(file.clone(), line)) {
                count += 1;
            }
        }
    }
    count
}

fn clamp_time(d: Duration) -> Duration {
    if d < MIN_EXECUTION_TIME {
        MIN_EXECUTION_TIME
    } else {
        d
    }
}

fn effective_seconds(d: Duration) -> f64 {
    clamp_time(d).as_secs_f64()
}

// ---------------------------------------------------------------------------
// Change recency weighting via git log
// ---------------------------------------------------------------------------

/// Query `git log` to determine how recently each file was last modified,
/// then compute exponential decay weights.
///
/// `half_life_days` controls how fast the weight decays: a file modified
/// `half_life_days` ago gets weight 0.5, 2*half_life_days ago gets 0.25, etc.
///
/// Returns a map from relative file path to weight in (0, 1].
pub fn compute_recency_weights(
    project_root: &Path,
    files: &[String],
    half_life_days: f64,
) -> Result<HashMap<String, f64>, RecencyError> {
    if files.is_empty() || half_life_days <= 0.0 {
        return Ok(HashMap::new());
    }

    let now = current_unix_timestamp(project_root)?;
    let mut weights = HashMap::with_capacity(files.len());

    for file in files {
        let last_modified = file_last_modified_timestamp(project_root, file)?;
        let age_days = (now - last_modified).max(0) as f64 / 86400.0;
        let weight = (-age_days.ln_1p().max(0.0) * std::f64::consts::LN_2 / half_life_days)
            .exp()
            .clamp(0.0, 1.0);
        // Simpler: weight = 2^(-age_days / half_life_days)
        let weight = 2.0_f64.powf(-age_days / half_life_days).clamp(0.0, 1.0);
        weights.insert(file.clone(), weight);
    }

    Ok(weights)
}

/// Errors from recency weight computation.
#[derive(Debug, thiserror::Error)]
pub enum RecencyError {
    #[error("git command failed: {0}")]
    GitFailed(String),
    #[error("I/O error: {0}")]
    Io(#[from] std::io::Error),
}

/// Get the current Unix timestamp via `date +%s`, avoiding chrono dependency.
fn current_unix_timestamp(root: &Path) -> Result<i64, RecencyError> {
    let output = Command::new("date")
        .arg("+%s")
        .current_dir(root)
        .output()?;
    if !output.status.success() {
        return Err(RecencyError::GitFailed("date +%s failed".to_string()));
    }
    String::from_utf8_lossy(&output.stdout)
        .trim()
        .parse::<i64>()
        .map_err(|e| RecencyError::GitFailed(format!("failed to parse timestamp: {e}")))
}

/// Get the Unix timestamp of the last git commit that touched `file`.
fn file_last_modified_timestamp(root: &Path, file: &str) -> Result<i64, RecencyError> {
    let output = Command::new("git")
        .args(["log", "-1", "--format=%ct", "--", file])
        .current_dir(root)
        .output()?;
    if !output.status.success() {
        return Err(RecencyError::GitFailed(format!(
            "git log for {file}: {}",
            String::from_utf8_lossy(&output.stderr)
        )));
    }
    let stdout = String::from_utf8_lossy(&output.stdout);
    let trimmed = stdout.trim();
    if trimmed.is_empty() {
        // File has no git history (new/untracked) — treat as "just now"
        return current_unix_timestamp(root);
    }
    trimmed
        .parse::<i64>()
        .map_err(|e| RecencyError::GitFailed(format!("failed to parse git timestamp: {e}")))
}

// ---------------------------------------------------------------------------
// Pipeline integration: convert TIA coverage map to TestCoverageInfo
// ---------------------------------------------------------------------------

/// Convert a TIA coverage map into `TestCoverageInfo` entries suitable for
/// prioritization. Since the TIA map tracks files (not lines), this creates
/// a synthetic line set covering lines 1..=`lines_per_file` for each file.
///
/// For real line-level coverage, callers should construct `TestCoverageInfo`
/// directly from instrumented coverage data.
pub fn from_coverage_map(
    entries: &std::collections::BTreeMap<String, crate::test_impact::TestEntry>,
    default_execution_time: Duration,
    lines_per_file: u32,
) -> Vec<TestCoverageInfo> {
    entries
        .iter()
        .map(|(test_id, entry)| {
            let covered_lines: HashMap<String, HashSet<u32>> = entry
                .files
                .keys()
                .map(|file| {
                    let lines: HashSet<u32> = (1..=lines_per_file).collect();
                    (file.clone(), lines)
                })
                .collect();
            TestCoverageInfo {
                test_id: test_id.clone(),
                covered_lines,
                execution_time: default_execution_time,
            }
        })
        .collect()
}

// ---------------------------------------------------------------------------
// Tests
// ---------------------------------------------------------------------------

#[cfg(test)]
mod tests {
    use super::*;

    fn make_test(id: &str, files_lines: &[(&str, &[u32])], ms: u64) -> TestCoverageInfo {
        let covered_lines = files_lines
