            .collect();
        TestCoverageInfo {
            test_id: id.to_string(),
            covered_lines,
            execution_time: Duration::from_millis(ms),
        }
    }

    #[test]
    fn empty_input_returns_empty_result() {
        let result = prioritize(&[], &PrioritizeConfig::default());
        assert!(result.ordered.is_empty());
        assert_eq!(result.total_lines_covered, 0);
        assert_eq!(result.total_time, Duration::ZERO);
        assert_eq!(result.budget_excluded, 0);
    }

    #[test]
    fn single_test_is_always_first() {
        let tests = vec![make_test("a", &[("f.rs", &[1, 2, 3])], 100)];
