        // Second test should have marginal_coverage = 2 (only the non-overlapping lines)
        assert_eq!(result.ordered[1].marginal_coverage, 2);
        assert_eq!(result.total_lines_covered, 7);
    }

    #[test]
    fn budget_excludes_tests_beyond_limit() {
        let tests = vec![
            make_test("fast", &[("f.rs", &[1, 2])], 100),
            make_test("slow", &[("g.rs", &[3, 4, 5])], 5000),
        ];
        let config = PrioritizeConfig {
            budget: Some(Duration::from_millis(200)),
            ..Default::default()
        };
        let result = prioritize(&tests, &config);
        // Only "fast" fits in the 200ms budget
        assert_eq!(result.ordered.len(), 1);
        assert_eq!(result.ordered[0].test_id, "fast");
        assert_eq!(result.budget_excluded, 1);
    }

    #[test]
    fn budget_none_includes_all_tests() {
        let tests = vec![
            make_test("a", &[("f.rs", &[1])], 1000),
            make_test("b", &[("g.rs", &[2])], 2000),
            make_test("c", &[("h.rs", &[3])], 3000),
        ];
        let result = prioritize(&tests, &PrioritizeConfig::default());
        assert_eq!(result.ordered.len(), 3);
        assert_eq!(result.budget_excluded, 0);
    }

    #[test]
    fn zero_execution_time_is_clamped() {
        let tests = vec![make_test("a", &[("f.rs", &[1])], 0)];
        let result = prioritize(&tests, &PrioritizeConfig::default());
        assert_eq!(result.ordered.len(), 1);
        // Score should use MIN_EXECUTION_TIME, not panic/infinity
        assert!(result.ordered[0].score.is_finite());
    }

    #[test]
    fn recency_weights_bias_toward_recent_files() {
        // Test A covers "old.rs" (weight=0.1), test B covers "new.rs" (weight=1.0).
        // Both have same line count and time, so B should win.
        let tests = vec![
            make_test("a", &[("old.rs", &[1, 2, 3, 4, 5])], 100),
            make_test("b", &[("new.rs", &[1, 2, 3, 4, 5])], 100),
        ];
        let mut recency = HashMap::new();
        recency.insert("old.rs".to_string(), 0.1);
        recency.insert("new.rs".to_string(), 1.0);
        let config = PrioritizeConfig {
            budget: None,
            recency_weights: recency,
        };
        let result = prioritize(&tests, &config);
        assert_eq!(result.ordered[0].test_id, "b");
    }

    #[test]
    fn total_time_is_sum_of_selected_tests() {
        let tests = vec![
            make_test("a", &[("f.rs", &[1])], 100),
            make_test("b", &[("g.rs", &[2])], 200),
        ];
        let result = prioritize(&tests, &PrioritizeConfig::default());
        assert_eq!(result.total_time, Duration::from_millis(300));
    }

    #[test]
    fn cumulative_time_is_monotonically_increasing() {
        let tests = vec![
            make_test("a", &[("f.rs", &[1])], 100),
            make_test("b", &[("g.rs", &[2])], 200),
            make_test("c", &[("h.rs", &[3])], 50),
        ];
        let result = prioritize(&tests, &PrioritizeConfig::default());
        for window in result.ordered.windows(2) {
            assert!(window[1].cumulative_time >= window[0].cumulative_time);
        }
    }

