mod proptests {
    use super::*;
    use proptest::prelude::*;

    fn arb_test_coverage_info() -> impl Strategy<Value = TestCoverageInfo> {
        (
            "[a-z_]{1,10}",
            prop::collection::hash_map(
                "[a-z/]{1,10}\\.rs",
                prop::collection::hash_set(1..=100u32, 0..=10),
                0..=3,
            ),
            1..=5000u64,
        )
            .prop_map(|(id, covered_lines, ms)| TestCoverageInfo {
                test_id: id,
                covered_lines,
                execution_time: Duration::from_millis(ms),
            })
    }

    proptest! {
        /// All input tests appear in the output (when no budget).
        #[test]
        fn all_tests_included_without_budget(
            tests in prop::collection::vec(arb_test_coverage_info(), 0..=15)
        ) {
            let config = PrioritizeConfig::default();
            let result = prioritize(&tests, &config);
            prop_assert_eq!(result.ordered.len(), tests.len());
            prop_assert_eq!(result.budget_excluded, 0);
        }

        /// Coverage is monotonically non-decreasing: each test can only add lines.
        #[test]
        fn coverage_monotonically_nondecreasing(
            tests in prop::collection::vec(arb_test_coverage_info(), 1..=10)
        ) {
            let result = prioritize(&tests, &PrioritizeConfig::default());
            let mut running_coverage = 0usize;
            for entry in &result.ordered {
                running_coverage += entry.marginal_coverage;
            }
            prop_assert_eq!(running_coverage, result.total_lines_covered);
        }

        /// Cumulative time is monotonically non-decreasing.
        #[test]
        fn cumulative_time_monotonic(
            tests in prop::collection::vec(arb_test_coverage_info(), 1..=10)
        ) {
            let result = prioritize(&tests, &PrioritizeConfig::default());
            for window in result.ordered.windows(2) {
                prop_assert!(window[1].cumulative_time >= window[0].cumulative_time);
            }
        }

        /// Total lines covered equals the union of all selected tests' lines.
        #[test]
        fn total_coverage_equals_union(
            tests in prop::collection::vec(arb_test_coverage_info(), 0..=10)
        ) {
            let result = prioritize(&tests, &PrioritizeConfig::default());

            // Compute the actual union
            let mut union: HashSet<(String, u32)> = HashSet::new();
            for test in &tests {
                for (file, lines) in &test.covered_lines {
                    for &line in lines {
                        union.insert((file.clone(), line));
                    }
                }
            }
            prop_assert_eq!(result.total_lines_covered, union.len());
        }

        /// Scores are always finite (no NaN/Infinity from division).
        #[test]
        fn scores_are_finite(
            tests in prop::collection::vec(arb_test_coverage_info(), 1..=10)
        ) {
            let result = prioritize(&tests, &PrioritizeConfig::default());
            for entry in &result.ordered {
                prop_assert!(entry.score.is_finite(), "score was not finite: {}", entry.score);
            }
        }

        /// Budget excludes tests: ordered.len() + budget_excluded == tests.len().
        #[test]
        fn budget_accounting(
            tests in prop::collection::vec(arb_test_coverage_info(), 0..=10),
            budget_ms in 0..=10000u64,
        ) {
            let config = PrioritizeConfig {
                budget: Some(Duration::from_millis(budget_ms)),
                ..Default::default()
            };
            let result = prioritize(&tests, &config);
            prop_assert_eq!(
                result.ordered.len() + result.budget_excluded,
                tests.len(),
                "ordered({}) + excluded({}) != total({})",
                result.ordered.len(),
                result.budget_excluded,
                tests.len(),
            );
        }

        /// No test appears twice in the output.
        #[test]
        fn no_duplicates(
            tests in prop::collection::vec(arb_test_coverage_info(), 0..=15)
        ) {
            let result = prioritize(&tests, &PrioritizeConfig::default());
            let ids: HashSet<_> = result.ordered.iter().map(|e| &e.test_id).collect();
            // Note: input tests might have duplicate IDs from proptest;
            // we check that the output has no more unique IDs than entries.
            prop_assert!(ids.len() <= result.ordered.len());
        }
    }
}

