/// Parse a human-readable duration string like "10s", "2m", "1m30s", "500ms".
fn parse_duration(s: &str) -> Result<std::time::Duration, String> {
    let s = s.trim();
    if s.is_empty() {
        return Err("empty duration string".to_string());
    }

    // Try parsing as pure seconds (e.g. "10")
    if let Ok(secs) = s.parse::<f64>() {
        if secs <= 0.0 {
            return Err(format!("duration must be positive: {s}"));
        }
        return Ok(std::time::Duration::from_secs_f64(secs));
    }

    let mut total_ms = 0u64;
    let mut num_buf = String::new();
    let mut found_unit = false;

    for ch in s.chars() {
        if ch.is_ascii_digit() || ch == '.' {
            num_buf.push(ch);
        } else {
            let value: f64 = num_buf
                .parse()
                .map_err(|_| format!("invalid number in duration: {s}"))?;
            num_buf.clear();
            found_unit = true;

            match ch {
                'h' => total_ms += (value * 3_600_000.0) as u64,
                'm' if !s.contains("ms") || num_buf.is_empty() => {
                    // Check if this 'm' is the start of "ms"
                    total_ms += (value * 60_000.0) as u64;
                }
                's' => total_ms += (value * 1_000.0) as u64,
                _ => return Err(format!("unknown duration unit '{ch}' in: {s}")),
            }
        }
    }

    // Handle trailing "ms" pattern more carefully
    // Re-parse with a simpler approach for common patterns
    if !found_unit && !num_buf.is_empty() {
        return Err(format!("missing unit in duration: {s}"));
    }

    if total_ms == 0 {
        // Fallback: try common patterns
        if let Some(secs_str) = s.strip_suffix('s') {
            if let Some(ms_str) = secs_str.strip_suffix('m') {
                if let Ok(ms) = ms_str.parse::<f64>() {
                    return Ok(std::time::Duration::from_secs_f64(ms / 1000.0));
                }
            }
            if let Ok(secs) = secs_str.parse::<f64>() {
                return Ok(std::time::Duration::from_secs_f64(secs));
            }
        }
        if let Some(min_str) = s.strip_suffix('m') {
            if let Ok(mins) = min_str.parse::<f64>() {
                return Ok(std::time::Duration::from_secs_f64(mins * 60.0));
            }
        }
        return Err(format!("could not parse duration: {s}"));
    }

    Ok(std::time::Duration::from_millis(total_ms))
}

