/// Parse a human-readable duration string like "10s", "2m", "1m30s", "500ms".
///
/// Supported suffixes: `ms` (milliseconds), `s` (seconds), `m` (minutes), `h` (hours).
/// A bare number without suffix is treated as seconds.
fn parse_duration(s: &str) -> Result<std::time::Duration, String> {
    let s = s.trim();
    if s.is_empty() {
        return Err("empty duration string".to_string());
    }

    // Bare number → seconds
    if let Ok(secs) = s.parse::<f64>() {
        if secs <= 0.0 {
            return Err(format!("duration must be positive: {s}"));
        }
        return Ok(std::time::Duration::from_secs_f64(secs));
    }

    // Use regex-free scanning: split into (number, unit) pairs.
    let mut total_secs = 0.0f64;
    let mut chars = s.chars().peekable();
    let mut found_any = false;

    while chars.peek().is_some() {
        // Consume digits/dots
        let mut num_str = String::new();
        while let Some(&ch) = chars.peek() {
            if ch.is_ascii_digit() || ch == '.' {
                num_str.push(ch);
                chars.next();
            } else {
                break;
            }
        }
        if num_str.is_empty() {
            return Err(format!("expected number in duration: {s}"));
        }
        let value: f64 = num_str.parse().map_err(|_| format!("invalid number in duration: {s}"))?;

        // Consume unit
        let mut unit = String::new();
        while let Some(&ch) = chars.peek() {
            if ch.is_ascii_alphabetic() {
                unit.push(ch);
                chars.next();
            } else {
                break;
            }
        }

        let multiplier = match unit.as_str() {
            "ms" => 0.001,
            "s" => 1.0,
            "m" | "min" => 60.0,
            "h" | "hr" => 3600.0,
            "" => return Err(format!("missing unit after {num_str} in: {s}")),
            other => return Err(format!("unknown duration unit '{other}' in: {s}")),
        };
        total_secs += value * multiplier;
        found_any = true;
    }

    if !found_any || total_secs <= 0.0 {
        return Err(format!("could not parse duration: {s}"));
    }

    Ok(std::time::Duration::from_secs_f64(total_secs))
}

