  1→//! Greedy submodular test case prioritization.
  2→//!
  3→//! Orders tests to maximize marginal coverage per unit of execution time.
  4→//! The algorithm is a standard greedy approximation for submodular set cover:
  5→//! at each step, pick the test with the highest ratio of *new lines covered*
  6→//! to *execution time*, mark those lines covered, and repeat.
  7→//!
  8→//! Supports optional change-recency weighting (recent git commits boost file
  9→//! importance) and time-budget truncation (`--budget`).
 10→
 11→use std::collections::{BTreeMap, HashMap, HashSet};
 12→use std::path::Path;
 13→use std::process::Command;
 14→use std::time::Duration;
 15→
 16→use serde::{Deserialize, Serialize};
 17→
 18→use crate::test_impact::CoverageMap;
 19→
 20→// ---------------------------------------------------------------------------
 21→// Constants
 22→// ---------------------------------------------------------------------------
 23→
 24→/// Default time budget when none is specified (0 means unlimited).
 25→pub const DEFAULT_BUDGET_SECS: u64 = 0;
 26→
 27→/// Half-life in days for recency weighting decay.
 28→/// Files modified within this many days receive ≥50% of max weight.
 29→pub const RECENCY_HALF_LIFE_DAYS: f64 = 14.0;
 30→
 31→/// Minimum recency weight (floor) so old files are never completely ignored.
 32→pub const MIN_RECENCY_WEIGHT: f64 = 0.1;
 33→
 34→/// Seconds per day (used for recency decay calculation).
 35→const SECS_PER_DAY: f64 = 86400.0;
 36→
 37→// ---------------------------------------------------------------------------
 38→// Error type
 39→// ---------------------------------------------------------------------------
 40→
 41→/// Errors from test prioritization.
 42→#[derive(Debug, thiserror::Error)]
 43→pub enum PrioritizeError {
 44→    #[error("I/O error: {0}")]
 45→    Io(#[from] std::io::Error),
 46→
 47→    #[error("invalid budget format: {0}")]
 48→    InvalidBudget(String),
 49→}
 50→
 51→// ---------------------------------------------------------------------------
 52→// Data types
 53→// ---------------------------------------------------------------------------
 54→
 55→/// A test case with its coverage footprint and timing metadata.
 56→#[derive(Debug, Clone, Serialize, Deserialize, PartialEq)]
 57→pub struct TestCase {
 58→    /// Unique test identifier (e.g. "crate::module::test_fn" or "shatter-ts::all").
 59→    pub id: String,
 60→    /// Source files this test covers (relative paths).
 61→    pub covered_files: Vec<String>,
 62→    /// Recorded execution duration (or estimate). Zero means unknown.
 63→    pub duration: Duration,
 64→}
 65→
 66→/// A prioritized test case with its computed score.
 67→#[derive(Debug, Clone, Serialize, Deserialize, PartialEq)]
 68→pub struct RankedTest {
 69→    pub test: TestCase,
 70→    /// Marginal weighted coverage at the time this test was selected.
 71→    pub marginal_coverage: f64,
 72→    /// Score = marginal_coverage / duration_secs at selection time.
 73→    pub score: f64,
 74→    /// Cumulative duration of all tests up to and including this one.
 75→    pub cumulative_duration: Duration,
 76→}
 77→
 78→/// Configuration for the prioritization algorithm.
 79→#[derive(Debug, Clone)]
 80→pub struct PrioritizeConfig {
 81→    /// Maximum total test execution time. Zero means unlimited.
 82→    pub budget: Duration,
 83→    /// Enable change-recency weighting from git log.
 84→    pub use_recency: bool,
 85→}
 86→
 87→impl Default for PrioritizeConfig {
 88→    fn default() -> Self {
 89→        Self {
 90→            budget: Duration::ZERO,
 91→            use_recency: false,
 92→        }
 93→    }
 94→}
 95→
 96→/// Result of a prioritization run.
 97→#[derive(Debug, Clone, Serialize, Deserialize)]
 98→pub struct PrioritizeResult {
 99→    /// Tests in priority order (highest value first).
100→    pub ordered: Vec<RankedTest>,
101→    /// Tests excluded because they exceeded the budget.
102→    pub excluded: Vec<TestCase>,
103→    /// Total duration of the ordered (included) tests.
104→    pub total_duration: Duration,
105→    /// The budget that was applied (zero if unlimited).
106→    pub budget: Duration,
107→}
108→
109→// ---------------------------------------------------------------------------
110→// Budget parsing
111→// ---------------------------------------------------------------------------
112→
113→/// Parse a budget string like "10s", "2m", "1m30s", or plain seconds "30".
114→pub fn parse_budget(s: &str) -> Result<Duration, PrioritizeError> {
115→    let s = s.trim();
116→    if s.is_empty() {
117→        return Err(PrioritizeError::InvalidBudget(
118→            "empty budget string".to_string(),
119→        ));
120→    }
121→
122→    // Try plain integer (seconds)
123→    if let Ok(secs) = s.parse::<u64>() {
124→        return Ok(Duration::from_secs(secs));
125→    }
126→
127→    let mut total_secs: u64 = 0;
128→    let mut current_num = String::new();
129→
130→    for ch in s.chars() {
131→        if ch.is_ascii_digit() || ch == '.' {
132→            current_num.push(ch);
133→        } else {
134→            let n: f64 = current_num.parse().map_err(|_| {
135→                PrioritizeError::InvalidBudget(format!("invalid number in '{s}'"))
136→            })?;
137→            current_num.clear();
138→            match ch {
139→                's' => total_secs += n as u64,
140→                'm' => total_secs += (n * 60.0) as u64,
141→                'h' => total_secs += (n * 3600.0) as u64,
142→                _ => {
143→                    return Err(PrioritizeError::InvalidBudget(format!(
144→                        "unknown unit '{ch}' in '{s}'"
145→                    )));
146→                }
147→            }
148→        }
149→    }
150→
151→    // Trailing digits without a unit → seconds
152→    if !current_num.is_empty() {
153→        let n: f64 = current_num.parse().map_err(|_| {
154→            PrioritizeError::InvalidBudget(format!("invalid number in '{s}'"))
155→        })?;
156→        total_secs += n as u64;
157→    }
158→
159→    if total_secs == 0 {
160→        return Err(PrioritizeError::InvalidBudget(format!(
161→            "budget '{s}' evaluates to zero"
162→        )));
163→    }
164→
165→    Ok(Duration::from_secs(total_secs))
166→}
