168→// ---------------------------------------------------------------------------
169→// Recency weighting
170→// ---------------------------------------------------------------------------
171→
172→/// Per-file weight based on how recently it was modified in git.
173→pub type RecencyWeights = HashMap<String, f64>;
174→
175→/// Query git log for the last-modified timestamp of each file and compute
176→/// exponential decay weights. Files modified recently get weight ~1.0,
177→/// older files decay toward `MIN_RECENCY_WEIGHT`.
178→pub fn compute_recency_weights(
179→    project_root: &Path,
180→    files: &[String],
181→) -> Result<RecencyWeights, PrioritizeError> {
182→    let now = std::time::SystemTime::now()
183→        .duration_since(std::time::UNIX_EPOCH)
184→        .map(|d| d.as_secs_f64())
185→        .unwrap_or(0.0);
186→
187→    let mut weights = HashMap::new();
188→
189→    for file in files {
190→        let age_days = git_file_age_days(project_root, file, now);
191→        let weight = recency_decay(age_days);
192→        weights.insert(file.clone(), weight);
193→    }
194→
195→    Ok(weights)
196→}
197→
198→/// Get the age in days of a file's most recent git commit.
199→/// Returns a large value if the file has no git history.
200→fn git_file_age_days(project_root: &Path, file: &str, now_epoch: f64) -> f64 {
201→    let output = Command::new("git")
202→        .args(["log", "-1", "--format=%ct", "--", file])
203→        .current_dir(project_root)
204→        .output();
205→
206→    match output {
207→        Ok(o) if o.status.success() => {
208→            let stdout = String::from_utf8_lossy(&o.stdout);
209→            let timestamp: f64 = stdout.trim().parse().unwrap_or(0.0);
210→            if timestamp > 0.0 {
211→                (now_epoch - timestamp) / SECS_PER_DAY
212→            } else {
213→                // No commits found for this file — treat as very old
214→                365.0
215→            }
216→        }
217→        _ => 365.0,
218→    }
219→}
220→
221→/// Exponential decay: weight = max(MIN_RECENCY_WEIGHT, 2^(-age/half_life)).
222→fn recency_decay(age_days: f64) -> f64 {
223→    let raw = 2.0_f64.powf(-age_days / RECENCY_HALF_LIFE_DAYS);
224→    raw.max(MIN_RECENCY_WEIGHT)
225→}
