227→// ---------------------------------------------------------------------------
228→// Core algorithm: greedy submodular maximization
229→// ---------------------------------------------------------------------------
230→
231→/// Build `TestCase` entries from a coverage map, using recorded durations
232→/// or a default estimate.
233→pub fn test_cases_from_coverage_map(
234→    coverage_map: &CoverageMap,
235→    recorded_durations: &BTreeMap<String, Duration>,
236→) -> Vec<TestCase> {
237→    let default_duration = Duration::from_secs(1);
238→
239→    coverage_map
240→        .data
241→        .entries
242→        .iter()
243→        .map(|(test_id, entry)| {
244→            let covered_files: Vec<String> = entry.files.keys().cloned().collect();
245→            let duration = recorded_durations
246→                .get(test_id)
247→                .copied()
248→                .unwrap_or(default_duration);
249→            TestCase {
250→                id: test_id.clone(),
251→                covered_files,
252→                duration,
253→            }
254→        })
255→        .collect()
256→}
257→
258→/// Greedy submodular maximization for test prioritization.
259→///
260→/// At each step, selects the test with the highest ratio of
261→/// (weighted new lines covered) / (execution time), adds it to the
262→/// result, marks its files as covered, and repeats.
263→///
264→/// If `budget` is non-zero, stops when adding the next test would
265→/// exceed the time budget.
266→pub fn prioritize(
267→    tests: &[TestCase],
268→    config: &PrioritizeConfig,
269→    recency_weights: Option<&RecencyWeights>,
270→) -> PrioritizeResult {
271→    // Dedup by test ID, keeping the first occurrence.
272→    let mut seen_ids = HashSet::new();
273→    let deduped: Vec<&TestCase> = tests
274→        .iter()
275→        .filter(|t| seen_ids.insert(&t.id))
276→        .collect();
277→
278→    let n = deduped.len();
279→    let mut selected: Vec<RankedTest> = Vec::with_capacity(n);
280→    let mut excluded: Vec<TestCase> = Vec::new();
281→    let mut covered: HashSet<String> = HashSet::new();
282→    let mut remaining: Vec<usize> = (0..n).collect();
283→    let mut cumulative = Duration::ZERO;
284→
285→    while !remaining.is_empty() {
286→        let mut best_idx: Option<usize> = None;
287→        let mut best_score: f64 = -1.0;
288→        let mut best_marginal: f64 = 0.0;
289→
290→        for &ri in &remaining {
291→            let test = deduped[ri];
292→            let marginal = marginal_coverage(&test.covered_files, &covered, recency_weights);
293→            let duration_secs = test.duration.as_secs_f64().max(0.001); // avoid div-by-zero
294→            let score = marginal / duration_secs;
295→
296→            if score > best_score {
297→                best_score = score;
298→                best_idx = Some(ri);
299→                best_marginal = marginal;
300→            }
301→        }
302→
303→        let Some(chosen_idx) = best_idx else {
304→            break;
305→        };
306→
307→        // If the best test adds zero marginal coverage, we're done
308→        // (all remaining tests are redundant).
309→        if best_marginal <= 0.0 {
310→            for &ri in &remaining {
311→                excluded.push(deduped[ri].clone());
312→            }
313→            break;
314→        }
315→
316→        let chosen = deduped[chosen_idx];
317→
318→        // Budget check: would adding this test exceed the budget?
319→        if !config.budget.is_zero() {
320→            let new_cumulative = cumulative + chosen.duration;
321→            if new_cumulative > config.budget {
322→                // This test doesn't fit — exclude it and continue
323→                // looking for smaller tests that might fit.
324→                remaining.retain(|&i| i != chosen_idx);
325→                excluded.push(chosen.clone());
326→                continue;
327→            }
328→        }
329→
330→        // Accept this test
331→        cumulative += chosen.duration;
332→        for file in &chosen.covered_files {
333→            covered.insert(file.clone());
334→        }
335→
336→        selected.push(RankedTest {
337→            test: chosen.clone(),
338→            marginal_coverage: best_marginal,
339→            score: best_score,
340→            cumulative_duration: cumulative,
341→        });
342→
343→        remaining.retain(|&i| i != chosen_idx);
344→    }
345→
346→    PrioritizeResult {
347→        ordered: selected,
348→        excluded,
349→        total_duration: cumulative,
350→        budget: config.budget,
351→    }
352→}
353→
354→/// Compute weighted marginal coverage: sum of weights for files not yet covered.
355→fn marginal_coverage(
356→    files: &[String],
357→    covered: &HashSet<String>,
358→    recency_weights: Option<&RecencyWeights>,
359→) -> f64 {
360→    let mut total = 0.0;
361→    for file in files {
362→        if !covered.contains(file) {
363→            let weight = recency_weights
364→                .and_then(|w| w.get(file))
365→                .copied()
366→                .unwrap_or(1.0);
367→            total += weight;
368→        }
369→    }
370→    total
371→}
