373→// ---------------------------------------------------------------------------
374→// Pipeline composition: TIA + prioritization
375→// ---------------------------------------------------------------------------
376→
377→/// Run the full TIA → prioritize pipeline:
378→/// 1. Load coverage map
379→/// 2. Query affected tests for changed files
380→/// 3. Build test cases from affected tests
381→/// 4. Optionally compute recency weights
382→/// 5. Prioritize with greedy submodular maximization
383→pub fn prioritize_affected(
384→    coverage_map: &CoverageMap,
385→    affected_tests: &[String],
386→    recorded_durations: &BTreeMap<String, Duration>,
387→    config: &PrioritizeConfig,
388→    project_root: Option<&Path>,
389→) -> Result<PrioritizeResult, PrioritizeError> {
390→    // Build test cases from the subset of affected tests
391→    let all_cases = test_cases_from_coverage_map(coverage_map, recorded_durations);
392→    let affected_set: HashSet<&str> = affected_tests.iter().map(|s| s.as_str()).collect();
393→    let cases: Vec<TestCase> = all_cases
394→        .into_iter()
395→        .filter(|tc| affected_set.contains(tc.id.as_str()))
396→        .collect();
397→
398→    // Optionally compute recency weights
399→    let recency = if config.use_recency {
400→        if let Some(root) = project_root {
401→            let all_files: Vec<String> = cases
402→                .iter()
403→                .flat_map(|tc| tc.covered_files.iter().cloned())
404→                .collect::<HashSet<_>>()
405→                .into_iter()
406→                .collect();
407→            Some(compute_recency_weights(root, &all_files)?)
408→        } else {
409→            None
410→        }
411→    } else {
412→        None
413→    };
414→
415→    Ok(prioritize(&cases, config, recency.as_ref()))
416→}
