419→// Display
420→// ---------------------------------------------------------------------------
421→
422→/// Format a prioritization result for human-readable CLI output.
423→pub fn format_prioritize_report(result: &PrioritizeResult, use_color: bool) -> String {
424→    let mut out = String::new();
425→
426→    let header = format!(
427→        "{} test(s) prioritized, total {:.1}s",
428→        result.ordered.len(),
429→        result.total_duration.as_secs_f64(),
430→    );
431→    if use_color {
432→        out.push_str(&format!("\x1b[1m{header}\x1b[0m\n"));
433→    } else {
434→        out.push_str(&format!("{header}\n"));
435→    }
436→
437→    if !result.budget.is_zero() {
438→        out.push_str(&format!(
439→            "Budget: {:.0}s\n",
440→            result.budget.as_secs_f64()
441→        ));
442→    }
443→    out.push('\n');
444→
445→    for (i, ranked) in result.ordered.iter().enumerate() {
446→        let idx = i + 1;
447→        let id = &ranked.test.id;
448→        let dur = ranked.test.duration.as_secs_f64();
449→        let files = ranked.test.covered_files.len();
450→        let marginal = ranked.marginal_coverage;
451→        let cum = ranked.cumulative_duration.as_secs_f64();
452→        out.push_str(&format!(
453→            "  {idx:>3}. {id}  ({dur:.1}s, {files} file(s), marginal={marginal:.2}, cum={cum:.1}s)\n"
454→        ));
455→    }
456→
457→    if !result.excluded.is_empty() {
458→        out.push('\n');
459→        let excl_header = format!("{} test(s) excluded:", result.excluded.len());
460→        if use_color {
461→            out.push_str(&format!("\x1b[33m{excl_header}\x1b[0m\n"));
462→        } else {
463→            out.push_str(&format!("{excl_header}\n"));
464→        }
465→        for tc in &result.excluded {
466→            out.push_str(&format!("  - {} ({:.1}s)\n", tc.id, tc.duration.as_secs_f64()));
467→        }
468→    }
469→
470→    out
471→}
